import{_ as t,c as a,o as s,a5 as n}from"./chunks/framework.CgT1UzWm.js";const u=JSON.parse(`{"title":"FAQ & Troubleshooting","titleTemplate":"NpgsqlRest","description":"Frequently asked questions about NpgsqlRest: missing endpoints, 404s, parameter naming, authentication, login endpoints, uploads, SSE, CORS, deployment, testing, performance, logging, and troubleshooting.","frontmatter":{"outline":[2,3],"title":"FAQ & Troubleshooting","titleTemplate":"NpgsqlRest","description":"Frequently asked questions about NpgsqlRest: missing endpoints, 404s, parameter naming, authentication, login endpoints, uploads, SSE, CORS, deployment, testing, performance, logging, and troubleshooting.","head":[["meta",{"name":"keywords","content":"npgsqlrest faq, npgsqlrest troubleshooting, endpoint not found, postgresql rest api questions, npgsqlrest 404, sql injection, npgsqlrest testing, npgsqlrest cors, postgresql login endpoint, file upload postgresql, server-sent events postgresql"}],["meta",{"property":"og:title","content":"NpgsqlRest FAQ & Troubleshooting"}],["meta",{"property":"og:description","content":"Frequently asked questions about NpgsqlRest."}],["meta",{"property":"og:type","content":"article"}],["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/guide/faq.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/guide/faq.html"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"NpgsqlRest FAQ & Troubleshooting"}],["meta",{"name":"twitter:description","content":"Frequently asked questions about NpgsqlRest."}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"FAQPage\\",\\"mainEntity\\":[{\\"@type\\":\\"Question\\",\\"name\\":\\"What is NpgsqlRest?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"NpgsqlRest is a self-contained executable that connects to PostgreSQL and automatically creates REST API endpoints from plain SQL script files, database functions, and procedures. No code generation step, no ORM — just SQL.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What PostgreSQL versions are supported?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"PostgreSQL 13 and newer. Discovery uses standard pgcatalog views that are stable across PostgreSQL versions.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What .NET version is required?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"None, for most users — the standalone executable and the Docker image are fully self-contained (AOT-compiled). The NuGet library targets .NET 10.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Is it safe from SQL injection?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes, by construction. Client-supplied values are always sent as PostgreSQL protocol parameters — never concatenated into SQL text. The SQL that runs is the SQL you wrote in the file, function, or procedure; a request can only choose parameter values, never SQL fragments. There is no query-building l\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How does NpgsqlRest compare to PostgREST or Supabase?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"See the detailed comparison blog post for a full feature-by-feature breakdown. The short version: PostgREST turns your tables into an API you query from the client; NpgsqlRest turns your SQL (files, functions, procedures) into an API you design.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I use it inside an existing ASP.NET Core application?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — the standalone executable is a wrapper around the NpgsqlRest NuGet middleware. In your own app: app.UseNpgsqlRest(new NpgsqlRestOptions(connectionString) { ... }). The plugins (SQL file source, TypeScript client, Dart client, OpenAPI, MCP) are separate NuGet packages.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can NpgsqlRest also serve my frontend (static files, SPA)?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — enable the StaticFiles section (root defaults to wwwroot) and it serves your SPA or static site from the same host as the API. AuthorizePaths puts paths behind login (with UnauthorizedRedirectPath for the redirect), and ParseContentOptions can template user claims and allow-listed environment \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I install NpgsqlRest?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"See the Installation Guide — standalone executable (Linux/macOS/Windows), an npm package (npm i npgsqlrest), a Docker image, or NuGet.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I run it in Docker?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Remember that localhost inside the container is the container — point the connection string at host.docker.internal (or the compose service name) to reach your database.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I connect to my database?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Set the connection string in appsettings.json: See Connection Settings for all options.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What if NpgsqlRest won't start because the database is down?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"By default TestConnectionStrings: true opens a test connection at startup. If it fails, the client retries on a 1, 3, 6, 12-second sequence for transient errors (connection drops, timeouts), then exits with an error if all retries fail. To skip the startup test, set TestConnectionStrings: false, or \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I use environment variables for configuration?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes. With ParseEnvironmentVariables in the Config section (enabled by default), use {ENVVARNAME} placeholders in configuration values — optional by default, {!ENVVARNAME} for required (startup error when unset, since 3.17.0), or {!ENVVARNAME:fallback} for a fallback value when unset (since 3.21.0). \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I change the port, bind address, or enable HTTPS?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Set the top-level Urls option — the default is http://localhost:8080; use http://0.0.0.0:8080 to listen on all interfaces (semicolon-separate multiple URLs). HTTPS is enabled with the Ssl section (redirection and HSTS are on once enabled) and a certificate configured under Kestrel — PFX, PEM, or the\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"My function doesn't appear as an endpoint\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Check these causes, most common first: 1. No HTTP annotation — since 3.17.0 the client defaults to CommentsMode: \\\\\\"OnlyAnnotated\\\\\\": a routine becomes an endpoint only if its comment contains an HTTP annotation (or a plugin annotation like @mcp). Add one — comment on function myfunc() is 'HTTP GET'; — \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"My SQL file doesn't appear as an endpoint\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Same CommentsMode rule as functions — the file needs an HTTP annotation by default. Two additional file-specific causes: 1. SkipPattern — files matching SqlFileSource.SkipPattern (default \\\\\\".test.sql\\\\\\") are excluded from endpoint discovery; they're test files for the test runner. 2. A describe error w\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"An endpoint exists but I get 404 — why?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"A 404 for an existing path is almost always parameter matching: a request must supply values for all parameters without defaults, with matching names — otherwise no endpoint matches and the response is 404 (not 400). Check: 1. Parameter names are converted — puserid becomes pUserId with the default \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Why did my read-only function become a POST endpoint?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"For functions, the HTTP method is inferred from PostgreSQL volatility — and VOLATILE is PostgreSQL's default, so a plain function maps to a mutation unless it is declared STABLE or IMMUTABLE, its name starts with get, contains get, or ends with get. Fix: declare read functions STABLE (good practice \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Are parameters sent in the query string or the request body?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"By HTTP method: GET and DELETE endpoints read parameters from the query string; POST, PUT, and other methods read a JSON body. Override per endpoint with @requestparamtype (querystring or bodyjson), or globally with DefaultRequestParamType. Sending parameters the wrong way means no endpoint matches \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Why are parameter and column names camelCased? How do I turn that off?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"The default NameConverter converts snakecase PostgreSQL names to camelCase JSON/URL names. Set \\\\\\"CamelCaseNames\\\\\\": false in the NpgsqlRest section to keep names exactly as they are in the database.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"My query returns one row — why do I get an array?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Endpoints return arrays by default. Annotate with @single to return the first row as a single JSON object, or combine with @nested for composite shapes. A single-column result set returns a flat value array ([\\\\\\"a\\\\\\",\\\\\\"b\\\\\\"]) — that's the UnnamedSingleColumnSet default in SQL File Source.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I return plain text, HTML, or CSV instead of JSON?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Use @raw — the column values are written to the response verbatim, with @separator and @newline for delimiter control, plus a Content-Type response header: There is also a table format output mode for ready-made HTML tables and Excel exports.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I return a specific HTTP status code from SQL?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"raise exception 'message'; surfaces as HTTP 400 by default (SQLSTATE P0001), insufficient privilege (42501) as 403, and command timeouts as 504. The whole mapping is configurable — ErrorHandlingOptions maps any PostgreSQL SQLSTATE to any status code through named policies, so raise exception ... usi\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I set response headers like \`Content-Disposition\` or \`Set-Cookie\`?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Write plain Header-Name: value lines in the comment — the same way the CSV example above sets Content-Type. Values support {parameter} substitution, so a dynamic download filename is one line: Content-Disposition: attachment; filename={name}.csv. Repeated header names combine into one header. See Re\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can one SQL file run multiple statements?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — a multi-statement file executes as a single batch (one database round-trip) and returns a JSON object with one key per result set: {\\\\\\"result1\\\\\\": ..., \\\\\\"result2\\\\\\": ...}. Name the keys with @result, drop a statement's output with @skip (it still executes), or return 204 No Content with @void; BEGIN/\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I customize the endpoint URL path?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Use the @path annotation — -- @path /custom/path in a SQL file, or the same line in a function comment. Versioning works the same way: @path /v2/orders.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I restrict access to an endpoint?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Use @authorize, optionally with roles: -- @authorize admin, manager. Mind the default posture, though: the standalone client ships with RequiresAuthorization: true, so every endpoint already requires an authenticated user and @allowanonymous opts out per endpoint. Set NpgsqlRest.RequiresAuthorizatio\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I expose tables and views directly, without writing any SQL?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"That's deliberately not the default model — NpgsqlRest wants you to design the API surface. The closest thing is a one-line SQL file per operation (select from myview; is a complete endpoint file). If you want fully automatic table CRUD, the NpgsqlRest.CrudSource NuGet plugin exists for library user\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Named or positional parameters in SQL files — which should I use?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Named (:name, since 3.19.0) for almost everything — the placeholder is the parameter name, so no @param naming annotations are needed, and the same name used repeatedly (even across statements) is one parameter: GET /api/get-reports?fromDate=...&toDate=... — done. Positional ($1, $2) remains fully s\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I make a parameter optional?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Give it a default. Functions: the native DEFAULT clause. SQL files: the @param annotation — -- @param status default 'active' or -- @param label default null. A parameter without a default is required, and a request missing it gets a 404 (no matching endpoint).\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I get the authenticated user's ID into a query?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Enable claim-to-parameter mapping with @userparameters and use a parameter whose name matches a claim mapping (default: userid → the user-id claim). With named parameters this needs nothing else: The value comes from the authenticated principal — the client cannot send or override it. (With position\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I send an array parameter?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"In a query string, repeat the key: ?ids=1&ids=2&ids=3 binds a three-element PostgreSQL array to an int[] parameter. In a JSON body, use a JSON array: {\\\\\\"ids\\\\\\": [1, 2, 3]}. Careful: repeating a key for a non-array parameter concatenates the values into one string instead.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I pass NULL in a query string?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"By default an empty value (?p=) is an empty string, not NULL (QueryStringNullHandling: \\\\\\"Ignore\\\\\\"). Change it per endpoint with @querystringnullhandling — emptystring makes ?p= mean NULL, nullliteral makes ?p=null mean NULL — or set the global default. For NULLs in text responses, @responsenull choose\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I read HTTP request headers in my SQL?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Add a json or text parameter named headers with a null default — the default RequestHeadersMode: \\\\\\"Parameter\\\\\\" fills it with all request headers as JSON. The Context mode makes headers readable anywhere via currentsetting('request.headers', true) instead. Per endpoint: @requestheadersmode.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I receive a raw request body (webhooks)?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Use @bodyparametername — the entire raw body (text, JSON, or bytea) is routed into that one parameter, and any other parameters automatically move to the query string.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I validate parameters before they reach the database?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — @validate using , runs immediately after parsing, before any database connection is opened. Built-in rules: notnull, notempty, required, email; custom Regex/MinLength/MaxLength rules with their own status codes and messages are defined in ValidationOptions. See Validation and @validate.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Error: \\\\\\"could not determine data type of parameter\\\\\\"\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"PostgreSQL couldn't infer the parameter's type from context (classic case: select setconfig('key', :value, true)). Give it a type hint: -- @param :value text (or -- @param $1 value text positionally), or add an inline cast in the SQL (:value::text). ---\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What authentication methods are supported?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Cookie-based auth, JWT Bearer tokens, Microsoft Bearer tokens, HTTP Basic Auth, Passkeys/WebAuthn (FIDO2), and external OAuth providers (Google, GitHub, LinkedIn, Microsoft, Facebook). All can be enabled simultaneously. See Authentication config.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I set up JWT authentication?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"See the Multiple Auth Schemes blog post for a complete walkthrough including login endpoints and RBAC.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I create a login endpoint?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Annotate a routine or SQL file with @login (usually together with @allowanonymous). It returns one row: a few special columns (status, scheme, body, hash) control the response, and every other column becomes a claim on the signed-in user — no row returned means 401. Verify the password yourself in S\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I log users out?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Annotate an endpoint with @logout. A void routine signs the caller out of all schemes; returned values are treated as scheme names to sign out of selectively.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I hash passwords when creating users?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Use -- @param hashedpassword is hash of password — the target parameter receives a PBKDF2-SHA256 hash of the source parameter before the routine runs, compatible with @login's built-in verification. The CLI can hash too: npgsqlrest --hash . See parameter hashing.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I add social login (Google, GitHub, Microsoft…)?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Enable Auth.External and add a provider block with ClientId and ClientSecret — Google, GitHub, LinkedIn, Microsoft, and Facebook are pre-configured; custom providers just set their URLs. After the OAuth flow, NpgsqlRest calls your configured LoginCommand function with the provider data, and its resu\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"My SPA on a different domain loses the session cookie — why?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Browsers drop cookies on cross-site requests unless the cookie is explicitly marked for it: set Auth.CookieSameSite: \\\\\\"None\\\\\\" together with Auth.CookieSecure: \\\\\\"Always\\\\\\" (and typically CookieDomain), and enable CORS with AllowCredentials: true and explicit origins. See Auth config and CORS. ---\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I push real-time events to the browser?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Server-Sent Events: annotate a routine with @sse and every raise info it makes is broadcast to subscribers connected to the endpoint's stream URL (/info by default). Control who receives events with @ssescope — all, authorize [roles], or matching. See the SSE guide and the real-time chat blog post.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I accept file uploads?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Enable UploadOptions and annotate the endpoint with @upload. Four handlers: largeobject (default — PostgreSQL Large Objects), filesystem, and csv/excel, which parse the file and run a SQL command per row (bulk ingestion without client code). Upload metadata arrives in a json parameter, and everythin\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can my SQL call an external HTTP API?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — HTTP Custom Types: create a composite type whose comment describes a request (GET https://api.example.com/{id}, headers, body), take it as a function parameter, and NpgsqlRest executes the call and fills the type's fields (body, statuscode, success, …) before your function runs. Requires HttpC\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can NpgsqlRest forward requests to another service (reverse proxy)?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — @proxy forwards the request to an upstream URL and streams the response back without touching the database; declare proxy parameters to transform the upstream response in SQL instead. @proxyout is the reverse: run your routine first, then send its result upstream (PDF rendering, ML inference, \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I expose functions as AI tools (MCP)?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Enable McpOptions and annotate routines with @mcp — only annotated routines are exposed, on a single /mcp endpoint (streamable HTTP). @mcp without an HTTP annotation makes a tool-only routine with no REST route, and @authorize roles are enforced on tool calls. Since 3.20.0, McpOptions.ToolSchemas ca\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can it generate a client — TypeScript, Dart, \`.http\` files, OpenAPI?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"All of them, regenerated on every watch cycle: ClientCodeGen emits typed TypeScript fetch modules with interfaces (and, since 3.20.0, optional TanStack Query hooks via ReactQuery), DartClientCodeGen (3.20.0) emits Dart modules for Flutter, HttpFileOptions writes ready-to-run .http files, and OpenApi\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I test my endpoints?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"With the built-in SQL test runner (since 3.19.0): write tests as plain .sql files and run npgsqlrest ./config.json --test. A test inserts fixtures, invokes a real endpoint in-process (full pipeline: routing, auth, parameter binding, serialization), asserts on the captured response with ordinary SQL,\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can tests run against a temporary database instead of my real one?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — that's the recommended CI setup. Setup steps create (and Teardown drops) a uniquely named database (apptest{rnd5}), migrations run as a step, and TestRunner.ConnectionName points the whole run at it. Template databases give per-test clones for perfect isolation. See the scenario catalog in the\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"My test fixtures need half the database inserted first — is there a better way?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes, and it's pure PostgreSQL: declare your foreign keys deferrable, then start the test with set constraints all deferred;. Deferred constraints are checked at COMMIT — and a test that ends in rollback never commits, so you can insert only the rows the test is about, in any order, referencing rows \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Is there a watch mode?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Two, with one flag. npgsqlrest ... --test --watch re-runs tests on changes — a changed test re-runs alone in milliseconds; a changed endpoint file or database routine rebuilds the endpoints in-process and re-runs everything, reporting exactly which endpoints appeared or dropped; Ctrl+C still tears t\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How fast is it?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Independent-methodology benchmarks measure thousands of requests per second on a single host — see the July 2026 benchmark series for detailed comparisons against PostgREST, Go, Rust, Spring Boot, FastAPI, and others under equalized conditions, including the methodology, per-framework analysis, and \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I enable caching?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Annotate with @cached (+ @cacheexpiresin 5 minutes). The backend (Memory, Redis, or HybridCache) is configured in Cache Options; per-user and per-parameter cache keys are supported. For conditional or tiered rules (\\\\\\"skip caching for admins\\\\\\", \\\\\\"shorter TTL for open-ended queries\\\\\\"), bundle settings int\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I enable response compression?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"See Response Compression.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I set up rate limiting?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Define policies in Rate Limiter config and apply them per endpoint with @ratelimiterpolicy.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Should I use the AOT or the JIT Docker image?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"The default AOT image (~60 MB compressed) starts instantly — best for development, CLI use, and scale-to-zero deployments. The JIT variant (vbilopav/npgsqlrest:latest-jit) is 50–100% faster under sustained high concurrency, at the cost of slower cold start and a ~110 MB compressed image — recommende\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I stream very large result sets?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Responses are flushed every 25 rows by default. @bufferrows 0 writes each row as it arrives (constant memory, immediate first byte); higher values trade memory for throughput. ---\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"My browser app gets CORS errors — how do I allow my frontend origin?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Enable the Cors section and list origins explicitly. AllowCredentials defaults to false — cookie-based auth needs it true, together with explicit AllowedOrigins (browsers reject combined with credentials): See CORS.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Behind nginx / Cloudflare the client IP is wrong\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Enable the ForwardedHeaders section so X-Forwarded-For/-Proto are honored — this affects logs, rate limiting, and the request.ipaddress context value. Set ForwardLimit to your proxy-chain depth and restrict trust with KnownProxies/KnownNetworks; with both lists empty, the headers are accepted from a\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I run behind PgBouncer / RDS Proxy / Supabase Pooler in transaction mode?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — set NpgsqlRest.WrapInTransaction: true. It wraps every request in BEGIN…COMMIT, which keeps setconfig state (claims, headers, user context) local to the request instead of leaking across pooled backends. Required for any pooler in transaction mode. See NpgsqlRest Options.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Is there a health endpoint for Kubernetes or load balancers?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Enable HealthChecks: /health (overall), /health/ready (includes a PostgreSQL connectivity check), and /health/live (no database check — so a database outage doesn't restart your pods). See Health Checks.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I route endpoints to a read replica or a second database?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — two mechanisms, depending on whether the databases have the same routines. For identical databases (read replicas, shards): define multiple named entries in ConnectionStrings, set NpgsqlRest.UseMultipleConnections: true, and pick per endpoint with @connection — metadata is still read once, and\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Does it retry transient errors?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Two layers, both on by default. Connection failures (startup included) retry on a 1, 3, 6, 12-second sequence, so the server survives the database starting after it does. Command execution retries transient SQLSTATEs — serialization failures (40001), deadlocks (40P01), dropped connections — on a 0, \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I see which endpoints are created and what options they have?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Set the NpgsqlRest log level to Debug — every endpoint logs as it is created, including which annotations were applied: Or list them without starting the server: npgsqlrest --endpoints.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I log the SQL each endpoint executes at runtime?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Two settings: \\\\\\"LogCommands\\\\\\": true in the NpgsqlRest section opts in, and the NpgsqlRest channel must be at Verbose (commands log at trace level): Add \\\\\\"LogCommandParameters\\\\\\": true to include parameter values (mind the sensitive-data implications in production — @securitysensitive obfuscates a specifi\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I see the metadata queries NpgsqlRest runs at startup?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Set the NpgsqlRest log level to Verbose — includes everything from Debug plus the raw pgcatalog discovery queries and the SQL-file describe phase. Useful when a function or file isn't being discovered and you need to see the underlying query and its filters.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I completely silence a logger?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Since 3.19.0 any Log:MinimalLevels entry accepts \\\\\\"Off\\\\\\" (aliases \\\\\\"None\\\\\\", \\\\\\"Silent\\\\\\"): Each named logger is independent — handy for muting the application channels while watching the test runner's NpgsqlRestTest channel.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Why do my RAISE messages appear in the server log?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"LogConnectionNoticeEvents is on by default — raise info/notice/warning from executing routines is written to the application log (the same mechanism that powers SSE). Set it to false in the NpgsqlRest section to silence them, or tune the format with LogConnectionNoticeEventsMode. See the Logging Gui\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I validate the configuration without starting the server?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"npgsqlrest --validate checks configuration keys and database connectivity, exiting 0 on success and 1 on failure — CI-friendly. Related: --config prints the fully resolved annotated configuration, --annotations lists every supported comment annotation as JSON, and --endpoints lists the endpoints tha\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I use the CLI to generate password hashes?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — npgsqlrest --hash generates a PBKDF2-SHA256 hash compatible with @login and password parameters. For HTTP Basic auth, npgsqlrest --basicauth outputs the header value to add to a request. ---\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Every endpoint returns 401 Unauthorized\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"That is the default posture, not a bug: the standalone client ships with RequiresAuthorization: true, so endpoints require an authenticated user unless annotated otherwise. Add @allowanonymous to public endpoints, or set NpgsqlRest.RequiresAuthorization to false and protect endpoints individually wi\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Startup warning: \\\\\\"Unknown configuration key\\\\\\"\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Almost always a typo in appsettings.json — keys are validated at startup. Run npgsqlrest --config to print the complete annotated configuration, or use the published JSON schema for editor autocompletion.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Error: \\\\\\"permission denied for schema\\\\\\"\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"The database user lacks USAGE on the schema: This is also a feature: run the server as a least-privilege role and endpoints can only do what that role can do.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Timeout errors (504 Gateway Timeout)\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Adjust the command timeout per endpoint with @commandtimeout 2 minutes, or globally in configuration.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"My POST body seems ignored — the endpoint returns 404\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Request bodies are read as JSON regardless of the Content-Type header — there is no content-type validation, and form-encoded/form-multipart bodies are never parsed (multipart files are only for @upload endpoints). A malformed JSON body logs a warning (Could not parse JSON body ...) and the request \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"413 Payload Too Large\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Kestrel caps request bodies at 30,000,000 bytes (~28.6 MB) by default — large uploads hit this before any NpgsqlRest setting. Raise Kestrel.Limits.MaxRequestBodySize in Server settings.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Timestamps shifted after upgrading to 3.16+\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Since 3.16.0, timestamps in JSON are treated as UTC by default (naive ISO strings assumed UTC, offset strings converted), so stored values no longer depend on the host's timezone. If you relied on the old host-local parsing, NpgsqlRest.JsonTimestampsAreUtc: false restores it — but treat that as a co\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Encrypted data is unreadable after restart\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Data Protection keys default to in-memory on Linux — configure persistent storage: See Data Protection config.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Leftover \`*_abcde\` test databases\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"The test runner drops its {rnd}-named databases on every exit path it can intercept — including Ctrl+C, SIGTERM, and hard startup errors. Leftovers mean a run was killed with SIGKILL (nothing can intercept that) or ran with Keep: true. Drop them manually:\\"}}]}"]]},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1782480183000}`),i={name:"guide/faq.md"};function o(r,e,l,d,h,p){return s(),a("div",null,e[0]||(e[0]=[n("",212)]))}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
